89	func (s *Store) Trend(metricID string) (TrendSummary, error) {
90		history, err := s.History(metricID)
91		if err != nil {
92			return TrendSummary{}, err
93		}
94		if len(history) == 0 {
95			return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
96		}
97		summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
98		var sum float64
99		for _, rec := range history {
100			if rec.Value < summary.Min {
101				summary.Min = rec.Value
102			}
103			if rec.Value > summary.Max {
104				summary.Max = rec.Value
105			}
106			sum += rec.Value
107			summary.UpdatedAt = rec.ObservedAt
108			if rec.Unit != "" {
109				summary.Unit = rec.Unit
110			}
111		}
112		summary.Count = len(history)
113		summary.Average = sum / float64(len(history))
114		return summary, nil
115	}
